import{_ as e,o as a,c as t,ag as o}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Editor | Dotfiles (IT)","titleTemplate":":title","description":"Alias shell per Neovim, VS Code, Vim, Nano, Emacs e Sublime Text. Modifica file piu velocemente con scorciatoie universali.","frontmatter":{"title":"Alias Editor | Dotfiles","description":"Alias shell per Neovim, VS Code, Vim, Nano, Emacs e Sublime Text. Modifica file piu velocemente con scorciatoie universali.","lang":"it-IT","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Editor preview","canonical":"/it/aliases/editor/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Editor","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Editor - Dotfiles (IT)","permalink":"/it/aliases/editor/","sidebar":true,"meta":[{"name":"keywords","content":"alias editor, neovim, vim, vscode, nano, emacs, sublime text, scorciatoie shell, dotfiles"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Alias shell per Neovim, VS Code, Vim, Nano, Emacs e Sublime Text. Modifica file piu velocemente con scorciatoie universali."},{"name":"twitter:title","content":"Alias Editor - Dotfiles"},{"name":"og:title","content":"Alias Editor - Dotfiles"},{"name":"og:description","content":"Alias shell per Neovim, VS Code, Vim, Nano, Emacs e Sublime Text. Modifica file piu velocemente con scorciatoie universali."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"it_IT"}]},"headers":[],"relativePath":"it/aliases/editor/index.md","filePath":"it/aliases/editor/index.md","lastUpdated":1773010926000}'),s={name:"it/aliases/editor/index.md"};function d(n,i,r,l,c,p){return a(),t("div",null,[...i[0]||(i[0]=[o(`<h1 id="alias-editor" tabindex="-1">Alias Editor <a class="header-anchor" href="#alias-editor" aria-label="Permalink to &quot;Alias Editor&quot;">​</a></h1><p>Scorciatoie per avviare e configurare il tuo editor di testo preferito.</p><h2 id="panoramica" tabindex="-1">Panoramica <a class="header-anchor" href="#panoramica" aria-label="Permalink to &quot;Panoramica&quot;">​</a></h2><p>Gli alias editor forniscono un&#39;interfaccia unificata per la modifica di testo su piu applicazioni. Definiti in <code>editor.aliases.sh</code> e caricati automaticamente da chezmoi, queste scorciatoie lavorano in armonia con <code>editor.sh</code> per rilevare e configurare il miglior editor disponibile sul tuo sistema.</p><p>Il sistema supporta Neovim, Visual Studio Code, Vim, Nano, Emacs, Sublime Text e Atom. Gli alias universali si adattano a qualunque editor sia attivo, mentre gli alias specializzati offrono funzionalita specifiche per editor.</p><h2 id="riferimento" tabindex="-1">Riferimento <a class="header-anchor" href="#riferimento" aria-label="Permalink to &quot;Riferimento&quot;">​</a></h2><h3 id="alias-universali" tabindex="-1">Alias universali <a class="header-anchor" href="#alias-universali" aria-label="Permalink to &quot;Alias universali&quot;">​</a></h3><p>Questi alias funzionano con qualsiasi editor configurato da <code>editor.sh</code>.</p><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>e</code></td><td>Comando modifica rapida</td></tr><tr><td><code>edit</code></td><td>Comando modifica standard</td></tr><tr><td><code>editor</code></td><td>Comando editor completo</td></tr><tr><td><code>mate</code></td><td>Comando stile TextMate</td></tr><tr><td><code>n</code></td><td>Alias modifica breve</td></tr><tr><td><code>v</code></td><td>Alias modifica tipo Vim</td></tr></tbody></table><h3 id="alias-neovim" tabindex="-1">Alias Neovim <a class="header-anchor" href="#alias-neovim" aria-label="Permalink to &quot;Alias Neovim&quot;">​</a></h3><p>Disponibili quando Neovim e l&#39;editor principale.</p><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>vi</code></td><td>Reindirizzato a Neovim</td></tr><tr><td><code>vim</code></td><td>Reindirizzato a Neovim</td></tr><tr><td><code>nvimrc</code></td><td>Modifica configurazione Vimscript Neovim</td></tr><tr><td><code>nvimlua</code></td><td>Modifica configurazione Lua Neovim</td></tr><tr><td><code>nvimconf</code></td><td>Apri directory configurazione Neovim</td></tr></tbody></table><h3 id="alias-visual-studio-code" tabindex="-1">Alias Visual Studio Code <a class="header-anchor" href="#alias-visual-studio-code" aria-label="Permalink to &quot;Alias Visual Studio Code&quot;">​</a></h3><p>Disponibili quando VS Code e installato.</p><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>vsc</code></td><td>Avvia VS Code</td></tr><tr><td><code>vsca</code></td><td>Aggiungi cartella alla finestra corrente</td></tr><tr><td><code>vscd</code></td><td>Confronta due file</td></tr><tr><td><code>vscn</code></td><td>Apri nuova finestra</td></tr><tr><td><code>vscr</code></td><td>Riusa finestra quando si aprono file</td></tr></tbody></table><h3 id="modifica-configurazione" tabindex="-1">Modifica configurazione <a class="header-anchor" href="#modifica-configurazione" aria-label="Permalink to &quot;Modifica configurazione&quot;">​</a></h3><p>La funzione <code>editrc</code> fornisce accesso rapido ai file di configurazione comuni.</p><table tabindex="0"><thead><tr><th>Comando</th><th>File target</th></tr></thead><tbody><tr><td><code>editrc bash</code></td><td><code>~/.bashrc</code></td></tr><tr><td><code>editrc zsh</code></td><td><code>~/.zshrc</code></td></tr><tr><td><code>editrc vim</code></td><td><code>~/.vimrc</code></td></tr><tr><td><code>editrc nvim</code></td><td>File init Neovim</td></tr><tr><td><code>editrc git</code></td><td><code>~/.gitconfig</code></td></tr><tr><td><code>editrc ssh</code></td><td><code>~/.ssh/config</code></td></tr></tbody></table><h3 id="esempi-di-utilizzo" tabindex="-1">Esempi di utilizzo <a class="header-anchor" href="#esempi-di-utilizzo" aria-label="Permalink to &quot;Esempi di utilizzo&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Modifica rapida un file usando l&#39;editor predefinito</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myfile.txt</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Modifica file di configurazione direttamente</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvimrc</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Quando si usa Neovim (vimscript)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvimlua</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Quando si usa Neovim (lua)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Usa VS Code per aprire una cartella in una nuova finestra</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vscn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/projects/my-project</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Modifica file di configurazione specifici</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">editrc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Modifica configurazione git</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">editrc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Modifica configurazione bash</span></span></code></pre></div>`,20)])])}const u=e(s,[["render",d]]);export{m as __pageData,u as default};
